#include <stdio.h>
#include <stdlib.h>
#include <string.h>
#include <unistd.h>
#include <fcntl.h>
#include <errno.h>

typedef struct FileHandleNode {
    int fd;
    char *description;
    struct FileHandleNode *next;
} FileHandleNode;

typedef struct FileHandlePool {
    FileHandleNode *head;
    int count;
    int initialized;
} FileHandlePool;

FileHandlePool* pool_create(void) {
    FileHandlePool *pool = (FileHandlePool *)calloc(1, sizeof(FileHandlePool));
    if (pool) {
        pool->head = NULL;
        pool->count = 0;
        pool->initialized = 1;
    }
    return pool;
}

int pool_add(FileHandlePool *pool, int fd, const char *description) {
    if (!pool || !pool->initialized) {
        fprintf(stderr, "Error: pool is not initialized\n");
        return -1;
    }

    if (fd < 0) {
        fprintf(stderr, "Error: invalid file descriptor %d\n", fd);
        return -1;
    }

    /* Check for duplicate fd */
    FileHandleNode *current = pool->head;
    while (current) {
        if (current->fd == fd) {
            fprintf(stderr, "Error: fd %d already exists in pool\n", fd);
            return -1;
        }
        current = current->next;
    }

    FileHandleNode *node = (FileHandleNode *)malloc(sizeof(FileHandleNode));
    if (!node) {
        fprintf(stderr, "Error: failed to allocate memory for node\n");
        return -1;
    }

    node->fd = fd;
    node->description = NULL;
    if (description) {
        node->description = strdup(description);
        if (!node->description) {
            fprintf(stderr, "Error: failed to allocate memory for description\n");
            free(node);
            return -1;
        }
    }

    node->next = pool->head;
    pool->head = node;
    pool->count++;

    printf("Added fd %d (%s) to pool. Total: %d\n",
           fd, description ? description : "no description", pool->count);

    return 0;
}

int pool_remove(FileHandlePool *pool, int fd) {
    if (!pool || !pool->initialized) {
        fprintf(stderr, "Error: pool is not initialized\n");
        return -1;
    }

    FileHandleNode *current = pool->head;
    FileHandleNode *prev = NULL;

    while (current) {
        if (current->fd == fd) {
            if (prev) {
                prev->next = current->next;
            } else {
                pool->head = current->next;
            }

            printf("Removing fd %d (%s) from pool.\n",
                   current->fd,
                   current->description ? current->description : "no description");

            /* Close the file descriptor */
            if (close(current->fd) == -1) {
                fprintf(stderr, "Warning: failed to close fd %d: %s\n",
                        current->fd, strerror(errno));
            }

            free(current->description);
            free(current);
            pool->count--;

            printf("Pool count: %d\n", pool->count);
            return 0;
        }
        prev = current;
        current = current->next;
    }

    fprintf(stderr, "Error: fd %d not found in pool\n", fd);
    return -1;
}

void pool_cleanup(FileHandlePool **pool_ptr) {
    if (!pool_ptr || !*pool_ptr) {
        printf("Cleanup called on NULL pool (safe no-op)\n");
        return;
    }

    FileHandlePool *pool = *pool_ptr;

    if (!pool->initialized) {
        printf("Cleanup called on already cleaned-up pool (safe no-op)\n");
        free(pool);
        *pool_ptr = NULL;
        return;
    }

    printf("Cleaning up pool with %d file handles...\n", pool->count);

    FileHandleNode *current = pool->head;
    while (current) {
        FileHandleNode *next = current->next;

        printf("  Closing fd %d (%s)\n",
               current->fd,
               current->description ? current->description : "no description");

        if (close(current->fd) == -1) {
            fprintf(stderr, "  Warning: failed to close fd %d: %s\n",
                    current->fd, strerror(errno));
        }

        free(current->description);
        free(current);
        current = next;
    }

    pool->head = NULL;
    pool->count = 0;
    pool->initialized = 0;

    printf("Cleanup complete.\n");

    free(pool);
    *pool_ptr = NULL;
}

void pool_print(const FileHandlePool *pool) {
    if (!pool || !pool->initialized) {
        printf("Pool: (not initialized or NULL)\n");
        return;
    }

    printf("=== File Handle Pool (%d entries) ===\n", pool->count);
    FileHandleNode *current = pool->head;
    int index = 0;
    while (current) {
        printf("  [%d] fd=%d, desc=\"%s\"\n",
               index++, current->fd,
               current->description ? current->description : "(none)");
        current = current->next;
    }
    printf("====================================\n");
}

